const express = require('express');
const helmet = require('helmet');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set security-related HTTP headers
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large payload attacks
app.use(express.json({ limit: '10kb' }));

// Disable the X-Powered-By header (also handled by helmet, but explicit is good)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate and sanitize query parameters if pagination is used
  const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 10, 1), 100);
  const offset = Math.max(parseInt(req.query.offset, 10) || 0, 0);

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({
    data: users.slice(offset, offset + limit),
    total: users.length,
    limit,
    offset,
  });
});

// --- 404 Handler ---

app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to recognize it as an error handler

app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal Server Error'
      : err.message,
  });
});

// --- Server Start ---

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

